.darma-loader-uiverse-tumbling-cube-route {
  position: relative;
  width: 150px;
  height: 150px;
  perspective: 900px;
  transform-style: preserve-3d;
}
.darma-loader-uiverse-tumbling-cube-route__cube {
  position: absolute;
  top: 0;
  left: 0;
  width: 72px;
  height: 72px;
  transform-style: preserve-3d;
  transform: translateZ(-36px);
  animation: darma-loader-uiverse-tumbling-cube-route-cubeRoute 4s cubic-bezier(.18,.56,.64,1) infinite;
}
.darma-loader-uiverse-tumbling-cube-route__side {
  position: absolute;
  width: 72px;
  height: 72px;
  background: color-mix(in srgb, var(--loader-color, #2d60ec) 82%, transparent);
  border: 2px solid color-mix(in srgb, var(--loader-secondary-color, #ffffff) 55%, transparent);
  box-shadow: inset 0 0 20px color-mix(in srgb, var(--loader-secondary-color, #ffffff) 18%, transparent);
}
.darma-loader-uiverse-tumbling-cube-route__side:nth-child(1) { transform: translateZ(36px); }
.darma-loader-uiverse-tumbling-cube-route__side:nth-child(2) { transform: rotateY(180deg) translateZ(36px); }
.darma-loader-uiverse-tumbling-cube-route__side:nth-child(3) { transform: rotateY(90deg) translateZ(36px); }
.darma-loader-uiverse-tumbling-cube-route__side:nth-child(4) { transform: rotateY(-90deg) translateZ(36px); }
.darma-loader-uiverse-tumbling-cube-route__side:nth-child(5) { transform: rotateX(90deg) translateZ(36px); }
.darma-loader-uiverse-tumbling-cube-route__side:nth-child(6) { transform: rotateX(-90deg) translateZ(36px); }
@keyframes darma-loader-uiverse-tumbling-cube-route-cubeRoute {
  0% { top: 0; left: 0; transform: translateZ(-36px); }
  25% { top: 78px; left: 78px; transform: translateZ(-36px) rotateX(-90deg) rotateZ(90deg); }
  50% { top: 0; left: 78px; transform: translateZ(-36px) rotateX(-180deg) rotateZ(180deg); }
  75% { top: 78px; left: 0; transform: translateZ(-36px) rotateX(-270deg) rotateZ(270deg); }
  100% { top: 0; left: 0; transform: translateZ(-36px) rotateX(-360deg) rotateZ(360deg); }
}

